            picker.PlaceholderEnd.Should().Be(null);
            picker.SeparatorIcon.Should().Be(Icons.Material.Filled.ArrowRightAlt);
        }

        [Test]
        public async Task DateRangePickerPlaceHolders()
        {
            var comp = Context.Render<MudDateRangePicker>();
