            var comp = Context.Render<MudDateRangePicker>(parameters => parameters
                .Add(p => p.Clearable, true)
                .Add(p => p.DateRange, initialRange)
                .Add(p => p.DateRangeChanged, (DateRange range) => changedRanges.Add(range)));

