                    .Add(picker => picker.EndInputAriaLabel, "Custom End")
            );

            comp.Find("input").GetAttribute("aria-label").Should().Be("Custom Start");
            comp.FindAll("input").Skip(1).First().GetAttribute("aria-label").Should().Be("Custom End");
        }

        [Test]
        public async Task MudRangeInputAriaLabels_DefaultValues()
        {
            var comp = Context.Render<MudRangeInput<string>>();

            // Default aria-labels should be the localized "Start" and "End"
            comp.Find("input").GetAttribute("aria-label").Should().Be("Start");
            comp.FindAll("input").Skip(1).First().GetAttribute("aria-label").Should().Be("End");
        }

        [Test]
        public async Task MudRangeInputAriaLabels_CustomValues()
        {
            var comp = Context.Render<MudRangeInput<string>>();
            await comp.SetParametersAndRenderAsync(parameters =>
                parameters
                    .Add(picker => picker.StartInputAriaLabel, "From")
                    .Add(picker => picker.EndInputAriaLabel, "To")
            );

            comp.Find("input").GetAttribute("aria-label").Should().Be("From");
            comp.FindAll("input").Skip(1).First().GetAttribute("aria-label").Should().Be("To");
        }
    }
